public static ETGIntegrationReversal construct()
{
    return new ETGIntegrationReversal();
}

/// <summary>
/// Below code is custmer reversal posting
/// </summary>
/// <param name = "_ARAPRef"></param>
public void postCustReversal(str _ARAPRef)
{
    str _arAPRefCust = _ARAPRef;
    ETG_ARAP_MSGHEADER headerMsg;
    ReasonTable reasonTable;
    ReasonCode reasonCodeOrg;
    ReasonRefRecID reasonRefRecIDOrg;
    CustTrans custTransReversal;
    ETGIntegrationReversal custReversal;

    select * from headerMsg where headerMsg.ETGARAPREF == _arAPRefCust;

    changecompany(headerMsg.ETGLegalEntity)
    {
        reasonCodeOrg = "CANCELLED";
        reasonTable = ReasonTable::find(reasonCodeOrg);
        reasonRefRecIDOrg = ReasonTableRef::createReasonTableRef(
        reasonTable.Reason, reasonTable.Description);

        custTransReversal = CustTrans::findFromInvoice(headerMsg.ETGARAPREF);

        if(custTransReversal.RecId && !custTransReversal.LastSettleVoucher)
        {
            Args args = new Args();
            args.record(custTransReversal);
            custReversal = ETGIntegrationReversal::construct();
            custReversal.parmReversalDate(str2Date(headerMsg.AXDocDate, 321));
            custReversal.parmReasonRefRecId(reasonRefRecIDOrg);
            custReversal.reversal(args);
        }
        else
        {
            throw error("The invoice %1 already has been settled", custTransReversal.Invoice);
        }
    }

}
